using System;
using System.Diagnostics;

public class PdfGenerator
{
    public bool GeneratePdf(string htmlPath, string pdfPath, PageSize pageSize = PageSize.A4, Orientation orientation = Orientation.Portrait)
    {
        if (string.IsNullOrEmpty(htmlPath) || string.IsNullOrEmpty(pdfPath))
            return false;

        var wkhtmltopdfPath = "wkhtmltopdf";
        var commandArgs = new[]
        {
            $"--page-size {pageSize}", 
            $"--orientation {orientation}", 
            htmlPath, 
            pdfPath
        };

        try
        {
            using (var process = Process.Start(new ProcessStartInfo
            {
                FileName = wkhtmltopdfPath,
                Arguments = string.Join(" ", commandArgs),
                RedirectStandardError = true,
                UseShellExecute = false,
                CreateNoWindow = true
            }))
            {
                process.WaitForExit();
                if (process.ExitCode != 0)
                    return false;
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"An error occurred: {ex.Message}");
            return false;
        }

        return true;
    }
}

public enum PageSize
{
    A4 = 1,
    Letter = 2
}

public enum Orientation
{
    Portrait = 1,
    Landscape = 2
}